import { IThemeManager } from '@jupyterlab/apputils';
/**
 * Initialization data for the jupyter_theme_atu extension.
 */
const plugin = {
    id: 'jupyter_theme_atu:plugin',
    autoStart: true,
    requires: [IThemeManager],
    activate: (app, manager) => {
        console.log('JupyterLab extension jupyter_theme_atu is activated!');
        const style = 'jupyter_theme_atu/index.css';
        manager.register({
            name: 'jupyter_theme_atu',
            isLight: false,
            load: () => manager.loadCSS(style),
            unload: () => Promise.resolve(undefined)
        });
    }
};
export default plugin;
